create table if not exists public.casino_point_transactions(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.casino_player_profiles(id) on delete cascade,transaction_type text not null,amount integer not null,balance_after integer not null,description text not null,created_at timestamptz not null default now());
create table if not exists public.casino_game_history(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.casino_player_profiles(id) on delete cascade,game_type text not null,room_code text,result text not null,points_delta integer not null default 0,created_at timestamptz not null default now());
create table if not exists public.casino_withdrawal_requests(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.casino_player_profiles(id) on delete cascade,requested_points integer not null check(requested_points>0),status text not null default 'pending' check(status in('pending','approved','rejected')),admin_note text,processed_by uuid references public.casino_player_profiles(id),created_at timestamptz not null default now(),processed_at timestamptz);
create table if not exists public.casino_notifications(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.casino_player_profiles(id) on delete cascade,notification_type text not null,title text not null,message text not null,is_read boolean not null default false,created_at timestamptz not null default now());
alter table public.casino_point_transactions enable row level security;alter table public.casino_game_history enable row level security;alter table public.casino_withdrawal_requests enable row level security;alter table public.casino_notifications enable row level security;
revoke all on public.casino_point_transactions,public.casino_game_history,public.casino_withdrawal_requests,public.casino_notifications from anon,authenticated;

create or replace function public.current_casino_profile_id() returns uuid language sql stable security definer set search_path=public as $$select profile_id from public.casino_profile_sessions where user_id=auth.uid();$$;
create or replace function public.get_my_profile_dashboard() returns jsonb language plpgsql stable security definer set search_path=public as $$declare v_id uuid:=public.current_casino_profile_id();v_result jsonb;begin if v_id is null then raise exception 'Player profile required';end if;select jsonb_build_object('player_code',p.player_code,'display_name',p.display_name,'points',p.points,'transactions',(select count(*) from public.casino_point_transactions where profile_id=v_id),'games',(select count(*) from public.casino_game_history where profile_id=v_id),'pending_withdrawals',(select count(*) from public.casino_withdrawal_requests where profile_id=v_id and status='pending'),'unread_notifications',(select count(*) from public.casino_notifications where profile_id=v_id and not is_read)) into v_result from public.casino_player_profiles p where p.id=v_id;return v_result;end;$$;
create or replace function public.list_my_point_transactions() returns setof public.casino_point_transactions language sql stable security definer set search_path=public as $$select * from public.casino_point_transactions where profile_id=public.current_casino_profile_id() order by created_at desc limit 200;$$;
create or replace function public.list_my_game_history() returns setof public.casino_game_history language sql stable security definer set search_path=public as $$select * from public.casino_game_history where profile_id=public.current_casino_profile_id() order by created_at desc limit 200;$$;
create or replace function public.list_my_casino_notifications() returns setof public.casino_notifications language sql stable security definer set search_path=public as $$select * from public.casino_notifications where profile_id=public.current_casino_profile_id() order by created_at desc limit 100;$$;
create or replace function public.mark_casino_notification_read(p_notification_id uuid) returns void language plpgsql security definer set search_path=public as $$begin update public.casino_notifications set is_read=true where id=p_notification_id and profile_id=public.current_casino_profile_id();end;$$;

create or replace function public.request_points_withdrawal(p_points integer) returns uuid language plpgsql security definer set search_path=public as $$declare v_id uuid:=public.current_casino_profile_id();v_balance integer;v_request uuid;begin if v_id is null then raise exception 'Player profile required';end if;if p_points<=0 then raise exception 'Invalid amount';end if;if exists(select 1 from public.casino_room_members where profile_id=v_id) then raise exception 'Leave your current room before requesting a withdrawal';end if;select points into v_balance from public.casino_player_profiles where id=v_id for update;if v_balance<p_points then raise exception 'Insufficient points';end if;update public.casino_player_profiles set points=points-p_points,updated_at=now() where id=v_id returning points into v_balance;insert into public.casino_withdrawal_requests(profile_id,requested_points) values(v_id,p_points) returning id into v_request;insert into public.casino_point_transactions(profile_id,transaction_type,amount,balance_after,description) values(v_id,'withdrawal_hold',-p_points,v_balance,'Puntos reservados para retiro');insert into public.casino_notifications(profile_id,notification_type,title,message) select profile_id,'withdrawal_request','Nueva solicitud de retiro','Un jugador solicitó retirar '||p_points||' puntos.' from public.casino_admins;return v_request;end;$$;

create or replace function public.admin_list_withdrawal_requests() returns table(request_id uuid,player_code text,display_name text,requested_points integer,status text,admin_note text,created_at timestamptz,processed_at timestamptz) language plpgsql stable security definer set search_path=public as $$begin if not public.is_casino_admin() then raise exception 'Administrator access required';end if;return query select w.id,p.player_code::text,p.display_name,w.requested_points,w.status,w.admin_note,w.created_at,w.processed_at from public.casino_withdrawal_requests w join public.casino_player_profiles p on p.id=w.profile_id order by w.created_at desc;end;$$;
create or replace function public.admin_decide_withdrawal(p_request_id uuid,p_decision text,p_admin_note text default null) returns void language plpgsql security definer set search_path=public as $$declare v_admin uuid:=public.current_casino_profile_id();v_request public.casino_withdrawal_requests%rowtype;v_balance integer;begin if not public.is_casino_admin() then raise exception 'Administrator access required';end if;if p_decision not in('approved','rejected') then raise exception 'Invalid decision';end if;select * into v_request from public.casino_withdrawal_requests where id=p_request_id for update;if not found or v_request.status<>'pending' then raise exception 'Request is no longer pending';end if;if p_decision='rejected' then update public.casino_player_profiles set points=points+v_request.requested_points,updated_at=now() where id=v_request.profile_id returning points into v_balance;insert into public.casino_point_transactions(profile_id,transaction_type,amount,balance_after,description) values(v_request.profile_id,'withdrawal_refund',v_request.requested_points,v_balance,'Retiro rechazado; puntos devueltos');end if;update public.casino_withdrawal_requests set status=p_decision,admin_note=nullif(trim(p_admin_note),''),processed_by=v_admin,processed_at=now() where id=p_request_id;insert into public.casino_notifications(profile_id,notification_type,title,message) values(v_request.profile_id,'withdrawal_'||p_decision,case when p_decision='approved' then 'Retiro aprobado' else 'Retiro rechazado' end,case when p_decision='approved' then 'El administrador marcó como entregados tus '||v_request.requested_points||' puntos.' else 'Tus '||v_request.requested_points||' puntos fueron devueltos.' end);end;$$;
create or replace function public.admin_player_activity(p_player_code text) returns jsonb language plpgsql stable security definer set search_path=public as $$declare v_id uuid;v_result jsonb;begin if not public.is_casino_admin() then raise exception 'Administrator access required';end if;select id into v_id from public.casino_player_profiles where player_code=upper(trim(p_player_code));if v_id is null then raise exception 'Player not found';end if;select jsonb_build_object('profile',(select to_jsonb(p)-'recovery_hash' from public.casino_player_profiles p where id=v_id),'transactions',(select coalesce(jsonb_agg(t order by t.created_at desc),'[]') from public.casino_point_transactions t where profile_id=v_id),'games',(select coalesce(jsonb_agg(g order by g.created_at desc),'[]') from public.casino_game_history g where profile_id=v_id),'withdrawals',(select coalesce(jsonb_agg(w order by w.created_at desc),'[]') from public.casino_withdrawal_requests w where profile_id=v_id)) into v_result;return v_result;end;$$;

create or replace function public.host_remove_room_member(p_room_id uuid,p_user_id uuid) returns void language plpgsql security definer set search_path=public as $$declare v_profile uuid;v_credits integer;v_old integer;v_game text;v_code text;begin if not public.is_casino_room_host(p_room_id) then raise exception 'Host only';end if;if p_user_id=auth.uid() then raise exception 'Host cannot remove self';end if;select m.profile_id,m.credits,p.points,r.game_type,r.invite_code into v_profile,v_credits,v_old,v_game,v_code from public.casino_room_members m join public.casino_player_profiles p on p.id=m.profile_id join public.casino_rooms r on r.id=m.room_id where m.room_id=p_room_id and m.user_id=p_user_id;if v_profile is not null then insert into public.casino_point_transactions(profile_id,transaction_type,amount,balance_after,description) values(v_profile,'room_settlement',v_credits-v_old,v_credits,'Saldo guardado al salir de la sala');insert into public.casino_game_history(profile_id,game_type,room_code,result,points_delta) values(v_profile,v_game,v_code,'Sesión finalizada',v_credits-v_old);update public.casino_player_profiles set points=v_credits,updated_at=now() where id=v_profile;insert into public.casino_notifications(profile_id,notification_type,title,message) values(v_profile,'room_exit','Saldo guardado','Tu saldo de '||v_credits||' puntos quedó guardado al salir.');end if;delete from public.casino_room_members where room_id=p_room_id and user_id=p_user_id;end;$$;
create or replace function public.leave_casino_room(p_room_id uuid) returns void language plpgsql security definer set search_path=public as $$declare rec record;begin if public.is_casino_room_host(p_room_id) then for rec in select m.profile_id,m.credits,p.points old_points,r.game_type,r.invite_code from public.casino_room_members m join public.casino_player_profiles p on p.id=m.profile_id join public.casino_rooms r on r.id=m.room_id where m.room_id=p_room_id loop insert into public.casino_point_transactions(profile_id,transaction_type,amount,balance_after,description) values(rec.profile_id,'room_settlement',rec.credits-rec.old_points,rec.credits,'Saldo guardado al cerrar la sala');insert into public.casino_game_history(profile_id,game_type,room_code,result,points_delta) values(rec.profile_id,rec.game_type,rec.invite_code,'Sala cerrada',rec.credits-rec.old_points);update public.casino_player_profiles set points=rec.credits,updated_at=now() where id=rec.profile_id;insert into public.casino_notifications(profile_id,notification_type,title,message) values(rec.profile_id,'room_closed','Sala finalizada','Tu saldo de '||rec.credits||' puntos quedó guardado.');end loop;update public.casino_rooms set status='closed',updated_at=now() where id=p_room_id;delete from public.casino_room_members where room_id=p_room_id;else select m.profile_id,m.credits,p.points old_points,r.game_type,r.invite_code into rec from public.casino_room_members m join public.casino_player_profiles p on p.id=m.profile_id join public.casino_rooms r on r.id=m.room_id where m.room_id=p_room_id and m.user_id=auth.uid();if found then insert into public.casino_point_transactions(profile_id,transaction_type,amount,balance_after,description) values(rec.profile_id,'room_settlement',rec.credits-rec.old_points,rec.credits,'Saldo guardado al abandonar la sala');insert into public.casino_game_history(profile_id,game_type,room_code,result,points_delta) values(rec.profile_id,rec.game_type,rec.invite_code,'Sesión finalizada',rec.credits-rec.old_points);update public.casino_player_profiles set points=rec.credits,updated_at=now() where id=rec.profile_id;insert into public.casino_notifications(profile_id,notification_type,title,message) values(rec.profile_id,'room_exit','Saldo guardado','Tu saldo de '||rec.credits||' puntos quedó guardado.');end if;delete from public.casino_room_members where room_id=p_room_id and user_id=auth.uid();end if;end;$$;

revoke all on function public.current_casino_profile_id(),public.get_my_profile_dashboard(),public.list_my_point_transactions(),public.list_my_game_history(),public.list_my_casino_notifications(),public.mark_casino_notification_read(uuid),public.request_points_withdrawal(integer),public.admin_list_withdrawal_requests(),public.admin_decide_withdrawal(uuid,text,text),public.admin_player_activity(text) from public;
grant execute on function public.current_casino_profile_id(),public.get_my_profile_dashboard(),public.list_my_point_transactions(),public.list_my_game_history(),public.list_my_casino_notifications(),public.mark_casino_notification_read(uuid),public.request_points_withdrawal(integer),public.admin_list_withdrawal_requests(),public.admin_decide_withdrawal(uuid,text,text),public.admin_player_activity(text) to authenticated;
notify pgrst,'reload schema';
